```cpp
#include <QObject>
#include <QByteArray>
#include <QQueue>

class Cache : public QObject
{
    Q_OBJECT

public:
    explicit Cache(QObject *parent = nullptr)
        : QObject(parent)
    {
    }

    void appendData(const QByteArray &data)
    {
        // 将接收到的数据添加到缓存中
        m_buffer.append(data);

        // 在缓存中查找报文头0xAABBCCDD
        int start = m_buffer.indexOf("AABBCCDD");

        while (start >= 0) {
            // 根据报文头的位置输出数据并释放内存
            QByteArray outputData = m_buffer.mid(0, start);
            // 这里可以对outputData进行一些处理，比如发出信号输出数据

            // 移动缓存的开始位置到报文头所在的位置
            m_buffer = m_buffer.mid(start);

            // 继续查找下一个报文头
            start = m_buffer.indexOf("AABBCCDD");
        }
    }

private:
    QByteArray m_buffer;
};

// 使用范例
int main()
{
    Cache cache;
    QByteArray receivedData = "0123456789AABBCCDD9876543210AABBCCDD1234567890";

    cache.appendData(receivedData); // 添加接收到的数据到缓存中

    return 0;
}
```

以上代码实现了一个简单的缓存类`Cache`，它将接收到的数据添加到一个`QByteArray`类型的缓存`m_buffer`中。每次接收新数据时，它都会在缓存中查找报文头0xAABBCCDD。如果找到了报文头，它会将报文头之前的数据输出（可以根据需求发出信号、打印数据等操作），然后释放这部分数据所占用的内存，并将缓存的开始位置移动到报文头所在的位置。重复这个过程，直到缓存中没有报文头为止。

