#include <QObject>
#include <QByteArray>
#include <QTcpSocket>

class TcpClientCache : public QObject
{
    Q_OBJECT

public:
    explicit TcpClientCache(QObject *parent = nullptr)
        : QObject(parent)
    {
        connect(&m_socket, &QTcpSocket::readyRead, this, &TcpClientCache::readData);
    }

    void connectToHost(const QString &host, quint16 port)
    {
        m_socket.connectToHost(host, port);
    }

signals:
    void dataReceived(const QByteArray &data);

private:
    void readData()
    {
        // 读取接收到的数据
        QByteArray data = m_socket.readAll();

        // 将接收到的数据添加到缓存中
        m_buffer.append(data);

        // 在缓存中查找报文头0xAABBCCDD
        int start = m_buffer.indexOf("AABBCCDD");

        while (start >= 0) {
            // 根据报文头的位置输出数据并释放内存
            QByteArray outputData = m_buffer.mid(0, start);
            emit dataReceived(outputData);

            // 移动缓存的开始位置到报文头所在的位置
            m_buffer = m_buffer.mid(start);

            // 继续查找下一个报文头
            start = m_buffer.indexOf("AABBCCDD");
        }
    }

    QTcpSocket m_socket;
    QByteArray m_buffer;
};

// 使用范例
int main()
{
    TcpClientCache cache;
    QString host = "127.0.0.1";
    quint16 port = 1234;

    QObject::connect(&cache, &TcpClientCache::dataReceived, [](const QByteArray &data) {
        // 处理接收到的数据，比如打印输出
        qDebug() << data;
    });

    cache.connectToHost(host, port); // 建立与服务器的连接

    return 0;
}
```

