#include <iostream>
#include <vector>

std::vector<unsigned short> restoreData(const std::vector<unsigned short>& inputData) {
    std::vector<unsigned short> outputData;

    unsigned short result = 0;
    int bitCount = 0;

    for (unsigned short data : inputData) {
        result <<= 14;  // 左移14位，为新数据留出空位
        result |= (data & 0x3FFF);  // 将低14位数据合并到result中
        bitCount += 14;

        // 当bitCount达到或超过16位时，保存高14位到输出数据，将低2位清零
        if (bitCount >= 16) {
            outputData.push_back((result & 0xFFFC) >> 2);
            result &= 0x0003;
            bitCount -= 16;
        }
    }

    // 处理剩余的数据
    if (bitCount > 0) {
        result <<= (16 - bitCount);  // 将剩余数据移到高位
        outputData.push_back((result & 0xFFFC) >> 2);
    }

    return outputData;
}

int main() {
    // 原始数据
    std::vector<unsigned short> inputData = {12345, 6789, 10111, 52222};

    // 还原数据
    std::vector<unsigned short> outputData = restoreData(inputData);

    // 打印结果
    for (unsigned short data : outputData) {
        std::cout << data << std::endl;
    }

    return 0;
}
```

